import assert from 'assert'
import { geo, geoFromHeaders, isInRegion, geoDistance } from './geo'

// Helper to create Headers with given entries
function makeHeaders(entries: Record<string, string>): Headers {
  return new Headers(entries)
}

// --- geo() with Vercel headers ---
{
  const headers = makeHeaders({
    'x-vercel-ip-city': 'San Francisco',
    'x-vercel-ip-country': 'US',
    'x-vercel-ip-country-region': 'CA',
    'x-vercel-ip-latitude': '37.7749',
    'x-vercel-ip-longitude': '-122.4194',
    'x-vercel-ip-timezone': 'America/Los_Angeles',
  })

  const result = geo({ headers })

  assert.strictEqual(result.city, 'San Francisco')
  assert.strictEqual(result.countryCode, 'US')
  assert.strictEqual(result.country, 'United States')
  assert.strictEqual(result.region, 'CA')
  assert.strictEqual(result.latitude, '37.7749')
  assert.strictEqual(result.longitude, '-122.4194')
  assert.strictEqual(result.timezone, 'America/Los_Angeles')

  console.log('✓ geo() with Vercel headers')
}

// --- geoFromHeaders() with Cloudflare fallback ---
{
  const headers = makeHeaders({
    'cf-ipcountry': 'GB',
  })

  const result = geoFromHeaders(headers)

  assert.strictEqual(result.countryCode, 'GB')
  assert.strictEqual(result.country, 'United Kingdom')
  assert.strictEqual(result.city, undefined)
  assert.strictEqual(result.region, undefined)
  assert.strictEqual(result.latitude, undefined)
  assert.strictEqual(result.longitude, undefined)
  assert.strictEqual(result.timezone, undefined)

  console.log('✓ geoFromHeaders() with Cloudflare fallback')
}

// --- Vercel header takes precedence over Cloudflare ---
{
  const headers = makeHeaders({
    'x-vercel-ip-country': 'DE',
    'cf-ipcountry': 'GB',
  })

  const result = geoFromHeaders(headers)

  assert.strictEqual(result.countryCode, 'DE')
  assert.strictEqual(result.country, 'Germany')

  console.log('✓ Vercel header takes precedence over Cloudflare')
}

// --- Missing headers return undefined fields ---
{
  const headers = makeHeaders({})
  const result = geo({ headers })

  assert.strictEqual(result.city, undefined)
  assert.strictEqual(result.country, undefined)
  assert.strictEqual(result.countryCode, undefined)
  assert.strictEqual(result.region, undefined)
  assert.strictEqual(result.latitude, undefined)
  assert.strictEqual(result.longitude, undefined)
  assert.strictEqual(result.timezone, undefined)

  console.log('✓ Missing headers return undefined fields')
}

// --- Country name lookup from countryCode ---
{
  const countryCodes: Record<string, string> = {
    US: 'United States',
    GB: 'United Kingdom',
    DE: 'Germany',
    FR: 'France',
    JP: 'Japan',
    CN: 'China',
    IN: 'India',
    BR: 'Brazil',
    AU: 'Australia',
    CA: 'Canada',
  }

  for (const [code, name] of Object.entries(countryCodes)) {
    const headers = makeHeaders({ 'x-vercel-ip-country': code })
    const result = geoFromHeaders(headers)
    assert.strictEqual(result.country, name, `Expected ${name} for ${code}`)
  }

  console.log('✓ Country name lookup from countryCode')
}

// --- Unknown country code returns undefined country name ---
{
  const headers = makeHeaders({ 'x-vercel-ip-country': 'ZZ' })
  const result = geoFromHeaders(headers)

  assert.strictEqual(result.countryCode, 'ZZ')
  assert.strictEqual(result.country, undefined)

  console.log('✓ Unknown country code returns undefined country name')
}

// --- isInRegion() with matching regions ---
{
  const geoData = { countryCode: 'US', country: 'United States' }

  assert.strictEqual(isInRegion(geoData, ['US', 'CA', 'GB']), true)
  assert.strictEqual(isInRegion(geoData, ['us', 'ca']), true) // case-insensitive
  assert.strictEqual(isInRegion(geoData, ['Us']), true) // mixed case

  console.log('✓ isInRegion() with matching regions')
}

// --- isInRegion() with non-matching regions ---
{
  const geoData = { countryCode: 'US', country: 'United States' }

  assert.strictEqual(isInRegion(geoData, ['DE', 'FR', 'JP']), false)
  assert.strictEqual(isInRegion(geoData, []), false)

  console.log('✓ isInRegion() with non-matching regions')
}

// --- isInRegion() with missing countryCode ---
{
  const geoData = {}

  assert.strictEqual(isInRegion(geoData, ['US']), false)

  console.log('✓ isInRegion() with missing countryCode')
}

// --- geoDistance() New York to London ~5570 km ---
{
  // New York: 40.7128° N, 74.0060° W
  // London: 51.5074° N, 0.1278° W
  const distance = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')

  assert.ok(
    Math.abs(distance - 5570) < 50,
    `Expected ~5570 km, got ${distance} km`
  )

  console.log('✓ geoDistance() New York to London ~5570 km')
}

// --- geoDistance() same point returns 0 ---
{
  const distance = geoDistance('0', '0', '0', '0')

  assert.strictEqual(distance, 0)

  console.log('✓ geoDistance() same point returns 0')
}

// --- geoDistance() Tokyo to Sydney ~7823 km ---
{
  // Tokyo: 35.6762° N, 139.6503° E
  // Sydney: -33.8688° S, 151.2093° E
  const distance = geoDistance('35.6762', '139.6503', '-33.8688', '151.2093')

  assert.ok(
    Math.abs(distance - 7823) < 50,
    `Expected ~7823 km, got ${distance} km`
  )

  console.log('✓ geoDistance() Tokyo to Sydney ~7823 km')
}

console.log('\nAll tests passed!')

